#!/usr/bin/env node
// Import local model benchmarks from DC telemetry database into models.json and hardware.json.
//
// Source: data/dc-local-benchmarks.json (regenerated by running the DB query in
// scripts/pull-dc-local-data.sh — or manually via dc-prod-db skill's db-query.mjs).
//
// Run: node scripts/import-dc-local-data.js

const fs = require('fs');
const path = require('path');

const REPO = path.resolve(__dirname, '..');
const models = JSON.parse(fs.readFileSync(path.join(REPO, 'data/models.json'), 'utf-8'));
const hardware = JSON.parse(fs.readFileSync(path.join(REPO, 'data/hardware.json'), 'utf-8'));
const dataset = JSON.parse(fs.readFileSync(path.join(REPO, 'data/dc-local-benchmarks.json'), 'utf-8'));

console.log(`Dataset pulled ${dataset.meta.pulled_at}: ${dataset.rows.length} rows`);

const SOURCE = 'https://github.com/desktop-commander/best-value-ai#dc-telemetry-data';

// ── GPU → hardware.json ID map ──────────────────────────────────────────────
// Keys are the exact DB strings (from metadata->hardwareInfo->gpu->model).
// Values are hardware.json IDs. null = skip (obsolete/irrelevant hardware).
const GPU_TO_HW = {
  // NVIDIA desktop
  'NVIDIA GeForce RTX 5090': 'rtx_5090',
  'NVIDIA GeForce RTX 5070': 'rtx_5070',
  'NVIDIA GeForce RTX 5060 Ti': 'rtx_5060_ti',
  'NVIDIA GeForce RTX 4090': 'rtx_4090',
  'NVIDIA GeForce RTX 4070': 'rtx_4070',
  'NVIDIA GeForce RTX 4060': 'rtx_4060',
  'NVIDIA GeForce RTX 3090': 'rtx_3090',
  'NVIDIA GeForce RTX 3080 Ti': 'rtx_3080_ti',
  'NVIDIA GeForce RTX 3080': 'rtx_3080',
  'NVIDIA GeForce RTX 3060': 'rtx_3060',
  'NVIDIA GeForce GTX 1660 SUPER': 'gtx_1660_super',
  'NVIDIA GeForce GTX 260': null, // too old (2008), skip
  // NVIDIA workstation / laptop
  'NVIDIA RTX 2000 Ada Generation': 'rtx_2000_ada',
  'NVIDIA GeForce RTX 4070 Laptop GPU': 'rtx_4070_laptop',
  'NVIDIA GeForce RTX 4060 Laptop GPU': 'rtx_4060_laptop',
  'NVIDIA RTX A3000 Laptop GPU': 'rtx_a3000_laptop',
  'NVIDIA RTX 500 Ada Generation Laptop GPU': 'rtx_500_ada_laptop',
  // AMD
  'AMD Radeon RX 7900 XTX': 'rx_7900_xtx',
  'AMD Radeon 780M Graphics': 'amd_780m_igpu',
  'AMD Radeon Pro 5500M': 'macbook_pro_2019_i9',
  // Apple Silicon
  'Apple M4 Pro': 'mac_m4_pro',
  'Apple M4': 'mac_m4_24gb',
  'Apple M3 Max': 'mac_m3_max_128gb',
  'Apple M2 Ultra': 'mac_m2_ultra',
  'Apple M2 Pro': 'mac_m2_pro',
  'Apple M2': 'mac_m2_8gb',
  'Apple M1 Max': 'mac_m1_max_64gb',
  'Apple M1 Pro': 'mac_m1_pro',
  'Apple M1': 'mac_m1_8gb',
  // Intel integrated
  'Intel(R) Iris(R) Xe Graphics': 'intel_iris_xe_laptop',
  'Intel(R) UHD Graphics 615': 'intel_uhd_615_laptop',
  'Intel(R) UHD Graphics': 'intel_uhd_laptop',
};

// ── NEW_HARDWARE: hardware entries to add if missing from hardware.json ────
// Using conservative street prices (USD). Year = release or refresh year.
const NEW_HARDWARE = {
  // NVIDIA desktop
  rtx_5060_ti: { name: 'RTX 5060 Ti', price: 430, vram: 16, year: 2025, source: 'https://www.nvidia.com/en-us/geforce/graphics-cards/50-series/rtx-5060-family/' },
  rtx_4070: { name: 'RTX 4070', price: 550, vram: 12, year: 2023, source: 'https://www.nvidia.com/en-us/geforce/graphics-cards/40-series/rtx-4070/' },
  rtx_3080: { name: 'RTX 3080', price: 400, vram: 10, year: 2020, notes: 'Used market price', source: 'https://www.nvidia.com/en-us/geforce/graphics-cards/30-series/rtx-3080-3080ti/' },
  rtx_3060: { name: 'RTX 3060', price: 280, vram: 12, year: 2021, source: 'https://www.nvidia.com/en-us/geforce/graphics-cards/30-series/rtx-3060-3060ti/' },
  gtx_1660_super: { name: 'GTX 1660 SUPER (used)', price: 120, vram: 6, year: 2019, notes: 'Used market price; very limited for modern LLMs', source: 'https://www.nvidia.com/en-us/geforce/graphics-cards/16-series/gtx-1660-super/' },
  // NVIDIA workstation/laptop
  rtx_2000_ada: { name: 'RTX 2000 Ada Generation', price: 650, vram: 16, year: 2024, notes: 'Professional workstation card', source: 'https://www.nvidia.com/en-us/design-visualization/rtx-2000-ada/' },
  rtx_4070_laptop: { name: 'RTX 4070 Laptop (full system)', price: 1500, vram: 8, year: 2023, notes: 'Laptop GPU, shared system RAM', source: 'https://www.nvidia.com/en-us/geforce/laptops/' },
  rtx_500_ada_laptop: { name: 'RTX 500 Ada Laptop (full system)', price: 1800, vram: 4, year: 2024, notes: 'Mobile workstation card', source: 'https://www.nvidia.com/en-us/design-visualization/rtx-500-ada-laptop/' },
  // AMD
  amd_780m_igpu: { name: 'AMD Radeon 780M (iGPU, full system)', price: 900, vram: 8, year: 2023, notes: 'Integrated GPU on Ryzen 7040/8000 series; uses shared system RAM', source: 'https://www.amd.com/en/products/apu/amd-ryzen-7-7840u' },
  // Apple Silicon
  mac_m4_pro: { name: 'Mac M4 Pro 24GB (full system)', price: 1999, vram: 24, year: 2024, notes: 'Unified memory', source: 'https://www.apple.com/shop/buy-mac/mac-mini' },
  mac_m2_ultra: { name: 'Mac M2 Ultra 64GB (full system)', price: 3999, vram: 64, year: 2023, notes: 'Mac Studio or Mac Pro, unified memory', source: 'https://www.apple.com/shop/refurbished/mac/mac-studio' },
  mac_m2_pro: { name: 'Mac M2 Pro 16GB (full system)', price: 1499, vram: 16, year: 2023, notes: 'MacBook Pro or Mac mini', source: 'https://www.apple.com/shop/refurbished/mac' },
  mac_m1_pro: { name: 'Mac M1 Pro 16GB (full system)', price: 1399, vram: 16, year: 2021, notes: '14/16-inch MacBook Pro, unified memory', source: 'https://www.apple.com/shop/refurbished/mac/macbook-pro' },
  mac_m1_8gb: { name: 'Mac M1 8GB (full system)', price: 699, vram: 8, year: 2020, notes: 'MacBook Air, MacBook Pro 13", Mac mini', source: 'https://www.apple.com/shop/refurbished/mac' },
  // Intel integrated
  intel_uhd_laptop: { name: 'Intel UHD Graphics Laptop (full system)', price: 450, vram: 16, year: 2019, notes: 'Generic Intel UHD integrated GPU, shared system RAM', source: 'https://www.intel.com/content/www/us/en/products/details/processors/core.html' },
};

// ── MODEL_MAP: DB model name → models.json ID, OR an inline model definition ──
// If value is a string, map to existing models.json entry (benchmarks come from that entry).
// If value is an object, create/update a new models.json entry with those fields.
// null = skip this model (extreme outliers only).
//
// Philosophy: we include community quants and custom variants — their DC data is real hardware
// performance, and the quality benchmarks will just be inherited from the base model via the
// `baseModelRef` field in models.json.

const MODEL_MAP = {
  // Gemma 4 family
  'gemma4:e4b': 'gemma-4-26b-a4b',          // official e4b quant = 26B A4B
  'gemma4:26b': 'gemma-4-26b-a4b',
  'bjoernb/gemma4-e4b-think:latest': 'gemma-4-26b-a4b', // thinking variant, same base
  'gemma-4-26b-a4b-it': 'gemma-4-26b-a4b',
  'google/gemma-4-26b-a4b': 'gemma-4-26b-a4b',
  'google/gemma-4-e4b': 'gemma-4-26b-a4b',
  'gemma4:latest': 'gemma-4-31b',            // default gemma4 points to 31B
  'gemma4:31b-cloud': 'gemma-4-31b',         // cloud variant — tagged is_cloud
  // Gemma 3 (smaller legacy)
  'gemma3:1b': 'gemma-3-1b',

  // Qwen 2.5 (older generation)
  'qwen2.5:14b': 'qwen-2.5-14b',
  'qwen2.5:7b': 'qwen-2.5-7b',
  'qwen2.5:3b': 'qwen-2.5-3b',
  'qwen2.5-coder:14b': 'qwen-2.5-coder-14b',
  'qwen2.5-coder:7b': 'qwen-2.5-coder-7b',
  'qwen2.5-coder:1.5b-base': 'qwen-2.5-coder-1.5b',
  'qwen2.5-coder:latest': 'qwen-2.5-coder-7b',  // default coder points to 7B
  'dagbs/qwen2.5-coder-14b-instruct-abliterated:q4_k_m': 'qwen-2.5-coder-14b',  // uncensored quant of same base

  // Qwen 3 family (3 is the between-generation, 3.5 is latest)
  'qwen3:1.7b': 'qwen-3-1.7b',
  'qwen3:4b': 'qwen-3-4b',
  'qwen3:8b': 'qwen-3-8b',
  'qwen3.5:2b': 'qwen-3.5-2b',
  'qwen3.5:9b': 'qwen-3.5-9b',
  'qwen3.5:9b-q8_0-20k': 'qwen-3.5-9b',           // 20k ctx, q8 quant — same base
  'qwen3.5:9b-q8_0-60k': 'qwen-3.5-9b',           // 60k ctx, q8 quant — same base
  'qwen3.5:latest': 'qwen3.5-27b',                 // default qwen3.5 in ollama = 27B
  'qwen3.5:27b-20k': 'qwen3.5-27b',                // 20k ctx variant
  'qwen3.5:35b-a3b-coding-nvfp4': 'qwen3.5-35b-a3b', // coding-tuned nvfp4 quant of 35B A3B
  'qwen/qwen3.5-35b-a3b': 'qwen3.5-35b-a3b',
  'qwen3.5-27b-ultra-uncensored-heretic-v1': 'qwen3.5-27b', // community uncensored of 27B
  'qwen/qwen3.5-9b': 'qwen-3.5-9b',
  'qwen3.5-9b-claude-4.6-opus-reasoning-distilled': 'qwen-3.5-9b', // distilled variant of 9B
  'qwen3-coder:30b': 'qwen-3-coder-30b',
  'qwen3-coder-64k:latest': 'qwen-3-coder-30b',   // 64k ctx variant of coder 30B
  'qwen/qwen3-coder-30b': 'qwen-3-coder-30b',
  'jaahas/qwen3.5-uncensored:latest': 'qwen3.5-27b',  // community uncensored of 27B default
  'Qwen:latest': 'qwen3.5-27b',                       // ambiguous default tag

  // DeepSeek
  'deepseek-r1:8b': 'deepseek-r1-distill-8b',

  // Cohere
  'command-r:35b': 'command-r-35b',

  // Meta Llama
  'llama3.2:3b': 'llama-3.2-3b',

  // GPT-OSS (OpenAI open-weights)
  'gpt-oss:20b': 'gpt-oss-20b',
  'gpt-oss:120b-cloud': 'gpt-oss-120b',  // cloud variant — tagged is_cloud

  // GLM
  'glm-4.7-flash:latest': 'glm-4.7-flash',

  // Liquid
  'liquid/lfm2-24b-a2b': 'lfm2-24b-a2b',

  // Nous Hermes
  'hermes3-64k:latest': 'hermes-3-8b', // Hermes 3 8B with 64k ctx

  // Cloud variants of real models (their hardware tps is network-bound, not compute)
  'deepseek-v3.2:cloud': 'deepseek-v3.2',
  'glm-4.7:cloud': 'glm-4.7',
  'glm-5:cloud': 'glm-5',
  'qwen3.5:397b-cloud': 'qwen3.5-397b',
  'kimi-k2.5:cloud': 'kimi-k2.5',
  'minimax-m2.5:cloud': 'minimax-m2.5',

  // Unclear / non-standard
  'octo-think:latest': null,    // unclear base model, unique community fine-tune
};

// ── Process ─────────────────────────────────────────────────────────────────

// 1) Add missing hardware entries
let hwAdded = 0;
for (const [id, hw] of Object.entries(NEW_HARDWARE)) {
  if (!hardware[id]) {
    hardware[id] = hw;
    hwAdded++;
    console.log(`  + hardware: ${id} (${hw.name}, $${hw.price})`);
  }
}

// 2) Track aggregation per (modelId, hwId) — multiple DB rows can map to the same slot
//    (e.g. qwen3.5:latest, qwen3.5:27b-20k, jaahas/qwen3.5-uncensored all → qwen3.5-27b)
//    We take a weighted average by message count.
const agg = new Map();  // key: `${modelId}|${hwId}` → { tpsSum, msgsSum, notes[], cloud }

let skipped = 0, unknownGpu = 0, unknownModel = 0, cloudRows = 0;

for (const entry of dataset.rows) {
  if (entry.is_cloud) cloudRows++;

  const modelId = MODEL_MAP[entry.model];
  if (modelId === null) {
    skipped++;
    continue;
  }
  if (modelId === undefined) {
    console.log(`  ? unknown model: ${entry.model} (${entry.msgs} msgs, ${entry.avg_tps} tps)`);
    unknownModel++;
    continue;
  }

  const hwId = GPU_TO_HW[entry.gpu];
  if (hwId === null) {
    skipped++;
    continue;
  }
  if (hwId === undefined) {
    console.log(`  ? unknown GPU: ${entry.gpu}`);
    unknownGpu++;
    continue;
  }

  const model = models[modelId];
  if (!model) {
    console.log(`  ! mapped modelId "${modelId}" not in models.json (from DB entry "${entry.model}")`);
    unknownModel++;
    continue;
  }

  // Skip cloud runs for hardware performance benchmarks — their TPS is network-bound
  // We still count them in cloudRows for reporting, but don't write them to local[] perf data
  if (entry.is_cloud) continue;

  const key = `${modelId}|${hwId}`;
  if (!agg.has(key)) {
    agg.set(key, { tpsSum: 0, msgsSum: 0, variants: [] });
  }
  const a = agg.get(key);
  a.tpsSum += entry.avg_tps * entry.msgs;
  a.msgsSum += entry.msgs;
  a.variants.push(entry.model);
}

// 3) Write aggregated benchmarks to models.json
let updated = 0, kept = 0;
for (const [key, a] of agg) {
  const [modelId, hwId] = key.split('|');
  const model = models[modelId];
  if (!model.local) model.local = {};

  const avg_tps = Math.round((a.tpsSum / a.msgsSum) * 10) / 10;
  const msgs = a.msgsSum;

  const existing = model.local[hwId];
  // Prefer new data if it has more messages than existing DC data,
  // OR if existing doesn't have DC data at all (we'll still overwrite since DC is real-world)
  if (existing && existing._dcMsgs && existing._dcMsgs > msgs) {
    console.log(`  = ${modelId} × ${hwId}: existing has ${existing._dcMsgs} msgs, new has ${msgs}, keeping`);
    kept++;
    continue;
  }

  const variantsNote = a.variants.length > 1
    ? `aggregated from ${a.variants.length} DB model variants: ${a.variants.join(', ')}`
    : `DB variant: ${a.variants[0]}`;

  model.local[hwId] = {
    tokensPerSec: avg_tps,
    source: SOURCE,
    _dcMsgs: msgs,
    _estimated: false,
    notes: `DC telemetry data (${dataset.meta.pulled_at}): ${msgs} msgs. ${variantsNote}`,
  };

  updated++;
  console.log(`  + ${modelId} × ${hwId}: ${avg_tps} tok/s (${msgs} msgs)${a.variants.length > 1 ? ` [${a.variants.length} variants]` : ''}`);
}

// 4) Write files
fs.writeFileSync(path.join(REPO, 'data/hardware.json'), JSON.stringify(hardware, null, 2) + '\n');
fs.writeFileSync(path.join(REPO, 'data/models.json'), JSON.stringify(models, null, 2) + '\n');

console.log('');
console.log('Summary:');
console.log(`  Dataset rows: ${dataset.rows.length} (${cloudRows} cloud, ${dataset.rows.length - cloudRows} local)`);
console.log(`  Hardware added: ${hwAdded}`);
console.log(`  Benchmarks updated: ${updated}`);
console.log(`  Benchmarks kept (existing has more msgs): ${kept}`);
console.log(`  Skipped (explicit null in map): ${skipped}`);
console.log(`  Unknown GPU: ${unknownGpu}`);
console.log(`  Unknown model: ${unknownModel}`);
